SELECT AVG(total_vaccinations) AS average_vaccinations_per_region
FROM (
  SELECT SUM(vax_full) AS total_vaccinations
  FROM vaccination_data
  GROUP BY teryt
) AS RegionVaccinationStats;

SELECT T1.teryt, T2.vaccine_type
FROM regions AS T1
JOIN vaccination_data AS T2 ON T1.teryt = T2.teryt
WHERE T2.vax_full = (
    SELECT MAX(vax_full) FROM vaccination_data
);
